const body = $json.body || $json;

// Frontend payload: { order_id, source, page_url, triggered_at }
return [{
  json: {
    trigger_source: 'frontend',
    order_id: body.order_id || '',
    source_type: body.source || 'unknown',
    triggered_at: body.triggered_at || new Date().toISOString(),
    payment_id: '',
    receipt_url: ''
  }
}];

const body = $json.body || $json;

const eventType = body.type || '';
const data = body.data || {};

// Square v2020 payload: data.object.payment
const payment = data.object?.payment || data.object || data.payment || {};

// Only process payment.updated
if (eventType !== 'payment.updated') {
  return [{ json: { skip: true, reason: 'Not payment.updated' } }];
}

if (payment.status !== 'COMPLETED') {
  return [{ json: { skip: true, reason: 'Payment not completed', actual_status: payment.status } }];
}

// Extract our order_id from reference_id
var orderId = payment.reference_id || '';
var squareOrderId = payment.order_id || '';

// Fallback to Square order_id
if (!orderId && squareOrderId) {
  orderId = squareOrderId;
}

// Square webhook does NOT include buyer email or line items
// We MUST lookup from DB
var totalCents = payment.total_money?.amount || payment.amount_money?.amount || 0;

return [{
  json: {
    trigger_source: 'square',
    order_id: orderId,
    square_order_id: squareOrderId,
    source_type: 'square-webhook',
    triggered_at: new Date().toISOString(),
    payment_id: payment.id || '',
    receipt_url: payment.receipt_url || '',
    total_cents: totalCents
  }
}];

// Route both triggers to same output
// No merge needed - just pass through
return [{ json: $json }];

// SQLite returns array of rows
const rows = $json;

if (!rows || rows.length === 0) {
  return [{ json: { error: 'NOT_FOUND', order_id: $json.order_id } }];
}

// Extract first row
const row = rows[0];

return [{ json: row }];

// DB is SOURCE OF TRUTH
const dbData = $json;

// Parse cart JSON
var cart = [];
try {
  cart = JSON.parse(dbData.cart_json || '[]');
} catch(e) {
  cart = [];
}

// Calculate display totals
var subtotal = ((dbData.subtotal_cents || 0) / 100).toFixed(2);
var tax = ((dbData.tax_cents || 0) / 100).toFixed(2);
var total = ((dbData.total_cents || 0) / 100).toFixed(2);

return [{
  json: {
    order_id: dbData.order_id,
    customer_name: dbData.customer_name || 'Valued Customer',
    email: dbData.customer_email || '',
    source: dbData.source || 'unknown',
    cart: cart,
    subtotal: subtotal,
    tax: tax,
    total: total
  }
}];

const cart = $json.cart || [];

let cartHtml = '<table style="width:100%;border-collapse:collapse;font-size:14px;">';

cart.forEach(function(item) {
  var price = parseFloat(item.price) || 0;
  var qty = parseInt(item.qty) || 1;
  var lineTotal = (price * qty).toFixed(2);
  cartHtml += '<tr>' +
    '<td style="padding:8px 0;color:#1F1B1D;">' + qty + 'x ' + (item.name || 'Item') + '</td>' +
    '<td style="text-align:right;color:#1F1B1D;">$' + lineTotal + '</td>' +
    '</tr>';
});

cartHtml += '<tr><td colspan="2"><hr style="border:none;border-top:1px solid #E6E1E1;margin:12px 0;" /></td></tr>' +
  '<tr><td>Subtotal</td><td style="text-align:right;">$' + $json.subtotal + '</td></tr>' +
  '<tr><td>Tax</td><td style="text-align:right;">$' + $json.tax + '</td></tr>' +
  '<tr style="font-weight:700;"><td>Total</td><td style="text-align:right;">$' + $json.total + '</td></tr>' +
  '</table>';

return [{
  json: Object.assign({}, $json, { CART_HTML: cartHtml })
}];

var data = $json;
var year = new Date().getFullYear();

// Detect order type from DB source
var orderType = 'Order';
var subjectLine = 'Your Utopia Deli Order Receipt';
var pickupText = 'We're preparing your order now.';

if (data.source === 'meal-prep') {
  orderType = 'Meal Prep Order';
  subjectLine = 'Your Utopia Deli Meal Prep Receipt';
  pickupText = 'Your meals are being prepared fresh for Thursday pickup.';
} else if (data.source === 'online-order') {
  orderType = 'Pickup Order';
}

var emailHtml = '<div style="font-family:Arial,sans-serif;max-width:600px;margin:auto;background:#FBF6F6;padding:24px;">' +
  '<div style="text-align:center;margin-bottom:24px;">' +
  '<a href="https://www.theutopiadeli.com" target="_blank">' +
  '<img src="https://cdn.shopify.com/s/files/1/0763/5042/3270/files/TheUtopiaDeliLogo_menu.png?v=1774974380" style="max-width:220px;" />' +
  '</a></div>' +
  '<p style="color:#590B3F;font-size:24px;font-weight:700;">Payment received ✅</p>' +
  '<p style="color:#754681;font-style:italic;">The Utopia Deli. It's just good food.</p>' +
  '<p style="font-size:14px;color:#1F1B1D;">Thanks for your payment, ' + data.customer_name + '. ' + pickupText + '</p>' +
  '<p style="font-size:14px;color:#1F1B1D;margin-top:16px;"><strong>' + orderType + ' #:</strong> ' + data.order_id + '</p>' +
  '<h3 style="color:#590B3F;margin-top:24px;">Order Summary</h3>' +
  data.CART_HTML +
  '<p style="margin-top:24px;font-size:12px;color:#8A8585;text-align:center;">' +
  '&copy; ' + year + '<br/>' +
  'The Utopia Deli<br/>' +
  '801 S Chester St, Little Rock, AR 72202<br/>' +
  '+1 (501) 551-5944</p>' +
  '</div>';

return [{
  json: Object.assign({}, data, {
    email_html: emailHtml,
    email_subject: subjectLine
  })
}];

return [{
  json: {
    success: true,
    order_id: $json.order_id,
    email_sent: true,
    timestamp: new Date().toISOString()
  }
}];

return [{
  json: {
    success: true,
    deduplicated: true,
    reason: 'Email already sent for this order',
    order_id: $json.order_id || 'unknown'
  }
}];

return [{
  json: {
    success: false,
    error: 'Order not found in database',
    order_id: $json.order_id || 'unknown'
  }
}];

return [{
  json: {
    success: false,
    error: 'No email address for customer',
    order_id: $json.order_id || 'unknown'
  }
}];
